var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐야, 이건?","JPN":"これは……どういうつもり？","ENG":"What's this?","TWN":"這是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그간 시키는 허드렛일도 다 해줬더니 그것만으론 부족하다는 거야?","JPN":"だいぶ難儀な仕事までこなしてるのに、それだけじゃ足りないの？","ENG":"I've done every little chore you asked. Isn't that enough?","TWN":"我幫你做了那麼多雜事，這樣還不夠是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......어쩔 수 없네. 그럼 그렇게 하자.","JPN":"……仕方ない。ならこうしよう。","ENG":"... Okay, then we'll do that.","TWN":"……沒辦法，就這樣吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사장님이 우릴 방해하지만 않는다면 나도 계속해서 도와줄 의향은 있어.","JPN":"社長が私達の邪魔さえしなければ、私も引き続き手を貸そうとは思ってる。","ENG":"I'm willing to cooperate so long as you stay out of our way.","TWN":"如果老闆不妨礙我們，我可以繼續幫你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아, 오해는 마. 이건 어디까지나 비즈니스가 아닌 개인적인 약속일 뿐이야.","JPN":"あ、誤解しないで。これはビジネスの話じゃなく、あくまでも個人的な約束だから。","ENG":"Oh, and I hope you understand that this is a personal arrangement, not an official one.","TWN":"啊，别誤會。這只是我個人的約定，不是商務層面的約定。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"민병대는 공식적으로 당신 같은 사람과 엮일 수 없어. 그렇게 되어서도 안되고.","JPN":"民兵隊は社長のような人間と付き合うわけにいかない。少なくとも大っぴらにはね。","ENG":"Officially, the Militia can't get involved with someone like you. It shouldn't.","TWN":"民兵隊不能且不可以和你這樣的人往來，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사장님이 좋은 사람이란 건 알아. 나도 잘 알고 있어.","JPN":"社長が善い人だってことくらい、私にも判る。","ENG":"I know you're a good person. I know it very well.","TWN":"我知道老闆是個好人，我當然知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그렇기 때문에 이런 식으로 밖에 도움을 줄 수 없다는 걸 이해해주길 바래.","JPN":"だからこそ、こんな形でしか協力できないってことをどうか判ってほしい。","ENG":"That's why I can only help you in this way. I hope you understand that.","TWN":"所以也希望你能理解我只能以這樣的方式幫你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"우린 당신이 추구하는 순수한 이념과는 결코 섞여선 안될 불순물 같은 거야.","JPN":"私達は、社長が追い求める理念とは相容れない不純物でしかないから。","ENG":"We're impurities that must stay separate from your pure ideals.","TWN":"我們就像雜質一樣，和你追求的單純理念是兩個世界的東西。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그리고 난 당신이 우리의 피투성이 손길에 더럽혀지지 않았으면 좋겠어.","JPN":"社長のことを、私達の血に塗れた手で汚したくはない。","ENG":"We don't want to stain you with our bloody hands.","TWN":"而且我不希望你被我們沾滿鮮血的雙手弄髒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"게다가 어차피 난 언젠간......","JPN":"それに、どうせいつか私は……","ENG":"Besides, I will someday...","TWN":"況且我總有一天……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......아니야. 이해해준다니 고마워.","JPN":"……とにかく、判ってくれたならいいの。礼を言わせて。","ENG":"Never mind. Thank you for your understanding.","TWN":"……没什麼，總之謝謝你能理解這些。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};